{
  "name": "Otis 856: Batch Rename",
  "description": "A professional batch file renaming tool inspired by Adobe Bridge. Sort, filter, define complex renaming rules, and download processed files individually or as a ZIP archive."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RuleType {
  TEXT = 'TEXT',
  SEQUENCE = 'SEQUENCE',
  ORIGINAL = 'ORIGINAL',
  DATE = 'DATE',
  REPLACE = 'REPLACE'
}

export interface Rule {
  id: string;
  type: RuleType;
  // Common
  value?: string;
  // Sequence specific
  startNumber?: number;
  padding?: number; // e.g. 3 for "001"
  // Original / Replace specific
  replaceTarget?: string;
  replaceWith?: string;
  caseSensitive?: boolean;
  // Date specific
  dateFormat?: string; // e.g., 'yyyy-MM-dd'
}

export interface FileData {
  id: string;
  file: File;
  originalName: string;
  newName: string;
  extension: string;
  size: number;
  lastModified: number;
}

export type SortField = 'name' | 'date' | 'size';
export type SortDirection = 'asc' | 'desc';

export interface SortConfig {
  field: SortField;
  direction: SortDirection;
}

import { Rule, RuleType, FileData } from '../types';
import { format } from 'date-fns';
import JSZip from 'jszip';

// Helper to pad numbers
const padNumber = (num: number, width: number): string => {
  const n = num.toString();
  return n.length >= width ? n : new Array(width - n.length + 1).join('0') + n;
};

// Main renaming engine
export const generateNewNames = (files: FileData[], rules: Rule[]): FileData[] => {
  return files.map((file, index) => {
    let nameParts: string[] = [];

    // If no rules, keep original
    if (rules.length === 0) {
      return { ...file, newName: file.originalName };
    }

    rules.forEach(rule => {
      switch (rule.type) {
        case RuleType.TEXT:
          if (rule.value) nameParts.push(rule.value);
          break;

        case RuleType.SEQUENCE:
          const start = rule.startNumber || 1;
          const currentNum = start + index;
          const padding = rule.padding || 1;
          nameParts.push(padNumber(currentNum, padding));
          break;

        case RuleType.ORIGINAL:
          let baseName = file.originalName.substring(0, file.originalName.lastIndexOf('.')) || file.originalName;
          nameParts.push(baseName);
          break;

        case RuleType.REPLACE:
           // Note: Replace usually acts on the "Original Name" part if it exists, 
           // but to simplify the bridge-like flow where you construct a string:
           // We will treat REPLACE as a modifier of the *current accumulated string* or allow it to be a standalone block?
           // Adobe Bridge "String Substitution" usually runs on the original filename.
           // However, in a block-based builder, "Original Name" is a block.
           // We will simplify: If the user adds a REPLACE block, it's ignored in this builder unless we implement a complex pipeline.
           // BETTER APPROACH for this UI: "Original Name" block has a "Replace" option inside it?
           // OR: We interpret "Original Name" block as the only place where we get the original name.
           // Let's stick to the blocks requested. 
           // If we add a REPLACE rule, let's assume it replaces text in the *Original Name* component. 
           // Actually, simpler implementation for now: The REPLACE rule applies to the *entire string generated so far*? No that's confusing.
           // Let's treat REPLACE as "Original Name with Replacement". 
           // So we won't have a standalone REPLACE rule type in the generator loop if we want to be strict.
           // But let's support "Text Substitution" on the original name if a user selects an option.
           // For this implementation, let's stick to: Text, Sequence, Original, Date.
           // If we need replace, we'll do it inside the 'Original' logic.
           break;

        case RuleType.DATE:
          try {
            const dateVal = new Date(file.lastModified);
            // Default to yyyyMMdd if no format provided
            const fmt = rule.dateFormat || 'yyyyMMdd'; 
            nameParts.push(format(dateVal, fmt));
          } catch (e) {
            // Fallback
            nameParts.push(Date.now().toString());
          }
          break;
      }
    });

    // Special Handling for REPLACE: 
    // If we wanted to implement search/replace, we would probably need to run it on the final string or just the original name part.
    // Given the constraints of a simple list builder, let's assume rules build the string.

    const baseName = nameParts.join('');
    // Always preserve extension logic for safety, unless we wanted to change it.
    // We append the extension at the end.
    const newName = `${baseName}.${file.extension}`;

    return { ...file, newName };
  });
};

export const createZip = async (files: FileData[]): Promise<Blob> => {
  const zip = new JSZip();

  // Track used names to avoid duplicates in ZIP
  const usedNames = new Set<string>();

  files.forEach(f => {
    let finalName = f.newName;

    // Simple duplicate prevention
    let counter = 1;
    while (usedNames.has(finalName)) {
      const dotIndex = finalName.lastIndexOf('.');
      const base = dotIndex !== -1 ? finalName.substring(0, dotIndex) : finalName;
      const ext = dotIndex !== -1 ? finalName.substring(dotIndex) : '';
      finalName = `${base}_${counter}${ext}`;
      counter++;
    }
    usedNames.add(finalName);

    zip.file(finalName, f.file);
  });

  return await zip.generateAsync({ type: 'blob' });
};

export const formatBytes = (bytes: number, decimals = 2) => {
  if (!+bytes) return '0 Bytes';

  const k = 1024;
  const dm = decimals < 0 ? 0 : decimals;
  const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];

  const i = Math.floor(Math.log(bytes) / Math.log(k));

  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(dm))} ${sizes[i]}`;
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  icon, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-md font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-otis-accent text-white hover:bg-otis-accentHover focus:ring-otis-accent",
    secondary: "bg-slate-700 text-slate-100 hover:bg-slate-600 focus:ring-slate-500",
    danger: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500",
    ghost: "bg-transparent text-slate-400 hover:text-white hover:bg-slate-800",
  };

  const sizes = {
    sm: "px-3 py-1.5 text-xs",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      {...props}
    >
      {icon && <span className="mr-2">{icon}</span>}
      {children}
    </button>
  );
};

import React from 'react';
import { Rule, RuleType } from '../types';
import { X, GripVertical } from 'lucide-react';

interface RuleItemProps {
  rule: Rule;
  index: number;
  onUpdate: (id: string, updates: Partial<Rule>) => void;
  onRemove: (id: string) => void;
}

export const RuleItem: React.FC<RuleItemProps> = ({ rule, onUpdate, onRemove }) => {

  const renderInputs = () => {
    switch (rule.type) {
      case RuleType.TEXT:
        return (
          <input
            type="text"
            value={rule.value || ''}
            onChange={(e) => onUpdate(rule.id, { value: e.target.value })}
            placeholder="Enter text..."
            className="flex-1 bg-slate-800 border border-slate-700 text-white text-sm rounded px-2 py-1 focus:ring-1 focus:ring-otis-accent focus:border-otis-accent outline-none"
          />
        );

      case RuleType.SEQUENCE:
        return (
          <div className="flex gap-2 items-center">
            <div className="flex flex-col">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Start</label>
              <input
                type="number"
                value={rule.startNumber}
                onChange={(e) => onUpdate(rule.id, { startNumber: parseInt(e.target.value) || 1 })}
                className="w-20 bg-slate-800 border border-slate-700 text-white text-sm rounded px-2 py-1 outline-none"
              />
            </div>
            <div className="flex flex-col">
              <label className="text-[10px] text-slate-500 uppercase font-bold">Digits</label>
              <select
                value={rule.padding}
                onChange={(e) => onUpdate(rule.id, { padding: parseInt(e.target.value) || 1 })}
                className="w-24 bg-slate-800 border border-slate-700 text-white text-sm rounded px-2 py-1 outline-none"
              >
                <option value={1}>1</option>
                <option value={2}>2 (01)</option>
                <option value={3}>3 (001)</option>
                <option value={4}>4 (0001)</option>
                <option value={5}>5 (00001)</option>
                <option value={6}>6 (000001)</option>
              </select>
            </div>
          </div>
        );

      case RuleType.DATE:
        return (
          <div className="flex flex-col w-full">
            <select
              value={rule.dateFormat}
              onChange={(e) => onUpdate(rule.id, { dateFormat: e.target.value })}
              className="w-full bg-slate-800 border border-slate-700 text-white text-sm rounded px-2 py-1 outline-none"
            >
              <option value="yyyyMMdd">YYYYMMDD</option>
              <option value="yyMMdd">YYMMDD</option>
              <option value="yyyy-MM-dd">YYYY-MM-DD</option>
              <option value="ddMMyy">DDMMYY</option>
              <option value="dd-MM-yy">DD-MM-YY</option>
              <option value="MMddyy">MMDDYY</option>
              <option value="HHmmss">HHMMSS (Time)</option>
            </select>
          </div>
        );

      case RuleType.ORIGINAL:
        return (
          <div className="text-slate-500 text-sm italic px-2">
            Using original filename
          </div>
        );

      default:
        return null;
    }
  };

  return (
    <div className="flex items-center gap-3 bg-slate-900/50 p-3 rounded-lg border border-slate-800 group hover:border-slate-700 transition-all">
      <div className="cursor-grab active:cursor-grabbing text-slate-600 hover:text-slate-400">
        <GripVertical size={16} />
      </div>

      <div className="w-32 flex-shrink-0">
        <span className="text-xs font-mono font-semibold text-otis-accent uppercase tracking-wider block mb-1">
          {rule.type}
        </span>
      </div>

      <div className="flex-1 flex items-center">
        {renderInputs()}
      </div>

      <button
        onClick={() => onRemove(rule.id)}
        className="text-slate-600 hover:text-red-500 p-1 rounded-md transition-colors opacity-0 group-hover:opacity-100 focus:opacity-100"
        title="Remove Rule"
      >
        <X size={16} />
      </button>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  FilePlus, 
  Download, 
  Trash2, 
  ArrowUpDown, 
  RefreshCw,
  Plus,
  FolderOpen,
  LayoutGrid,
  List as ListIcon,
  Archive
} from 'lucide-react';
import { Rule, RuleType, FileData, SortConfig } from './types';
import { generateNewNames, createZip, formatBytes } from './utils/fileHelpers';
import { Button } from './components/Button';
import { RuleItem } from './components/RuleItem';
import JSZip from 'jszip';
import { saveAs } from 'file-saver';

// We need file-saver for client side downloading from blobs effectively
// Since I can't npm install in this environment description, I will implement a simple download helper or use the native anchor tag method if file-saver is strictly external.
// Actually, standard anchor download is fine for modern browsers.

const App: React.FC = () => {
  // State
  const [files, setFiles] = useState<FileData[]>([]);
  const [rules, setRules] = useState<Rule[]>([]);
  const [sortConfig, setSortConfig] = useState<SortConfig>({ field: 'name', direction: 'asc' });
  const [isProcessing, setIsProcessing] = useState(false);

  // Initialize with a default rule
  useEffect(() => {
    if (rules.length === 0) {
      setRules([{ id: uuidv4(), type: RuleType.ORIGINAL }]);
    }
  }, []);

  // Handlers
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files.length > 0) {
      const newFiles: FileData[] = Array.from(event.target.files).map(file => {
        const lastDot = file.name.lastIndexOf('.');
        const name = lastDot !== -1 ? file.name.substring(0, lastDot) : file.name;
        const ext = lastDot !== -1 ? file.name.substring(lastDot + 1) : '';

        return {
          id: uuidv4(),
          file,
          originalName: file.name,
          newName: file.name, // Initial placeholder
          extension: ext,
          size: file.size,
          lastModified: file.lastModified
        };
      });

      setFiles(prev => sortFiles([...prev, ...newFiles], sortConfig));
    }
    // Reset input
    event.target.value = '';
  };

  const handleAddRule = (type: RuleType) => {
    const newRule: Rule = {
      id: uuidv4(),
      type,
      value: '',
      startNumber: 1,
      padding: 3,
      dateFormat: 'yyyyMMdd'
    };
    setRules(prev => [...prev, newRule]);
  };

  const handleUpdateRule = (id: string, updates: Partial<Rule>) => {
    setRules(prev => prev.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const handleRemoveRule = (id: string) => {
    setRules(prev => prev.filter(r => r.id !== id));
  };

  const handleSort = (field: 'name' | 'date' | 'size') => {
    const isSameField = sortConfig.field === field;
    const direction = isSameField && sortConfig.direction === 'asc' ? 'desc' : 'asc';
    const config: SortConfig = { field, direction };
    setSortConfig(config);
    setFiles(prev => sortFiles(prev, config));
  };

  const sortFiles = (fileList: FileData[], config: SortConfig) => {
    return [...fileList].sort((a, b) => {
      let valA: string | number = '';
      let valB: string | number = '';

      if (config.field === 'name') {
        valA = a.originalName.toLowerCase();
        valB = b.originalName.toLowerCase();
      } else if (config.field === 'date') {
        valA = a.lastModified;
        valB = b.lastModified;
      } else if (config.field === 'size') {
        valA = a.size;
        valB = b.size;
      }

      if (valA < valB) return config.direction === 'asc' ? -1 : 1;
      if (valA > valB) return config.direction === 'asc' ? 1 : -1;
      return 0;
    });
  };

  // Derived state: Preview
  const previewFiles = useMemo(() => {
    return generateNewNames(files, rules);
  }, [files, rules]);

  const handleClearFiles = () => setFiles([]);

  const handleDownloadZip = async () => {
    if (previewFiles.length === 0) return;
    setIsProcessing(true);
    try {
      const blob = await createZip(previewFiles);
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'renamed_files_otis856.zip';
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error("Zip failed", err);
      alert("Failed to create ZIP file.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans text-slate-300">
      {/* Header */}
      <header className="h-16 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-otis-accent rounded flex items-center justify-center text-slate-900 font-bold font-mono">
            8
          </div>
          <div>
            <h1 className="text-sm font-bold text-white tracking-wide uppercase">Otis 856</h1>
            <p className="text-[10px] text-slate-500 font-mono">BATCH RENAME UTILITY</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <a href="#" className="text-xs text-slate-500 hover:text-white transition-colors">Documentation</a>
          <div className="h-4 w-px bg-slate-700"></div>
          <div className="flex items-center gap-2 text-xs text-slate-400">
            <span className="w-2 h-2 rounded-full bg-green-500"></span>
            System Ready
          </div>
        </div>
      </header>

      {/* Main Layout */}
      <main className="flex-1 flex flex-col lg:flex-row overflow-hidden">

        {/* LEFT PANEL: CONFIGURATION */}
        <aside className="w-full lg:w-[420px] bg-slate-900 border-r border-slate-800 flex flex-col z-20 shadow-xl">
          <div className="p-5 border-b border-slate-800 flex justify-between items-center">
             <h2 className="text-sm font-semibold text-white uppercase tracking-wider">Naming Rules</h2>
             <span className="text-xs text-slate-500 bg-slate-800 px-2 py-0.5 rounded-full">{rules.length} Active</span>
          </div>

          <div className="flex-1 overflow-y-auto p-5 space-y-3">
            {rules.map((rule, idx) => (
              <RuleItem
                key={rule.id}
                rule={rule}
                index={idx}
                onUpdate={handleUpdateRule}
                onRemove={handleRemoveRule}
              />
            ))}

            {rules.length === 0 && (
              <div className="text-center py-10 border-2 border-dashed border-slate-800 rounded-lg">
                <p className="text-slate-500 text-sm">No active rules.</p>
                <p className="text-slate-600 text-xs mt-1">Files will remain unchanged.</p>
              </div>
            )}
          </div>

          <div className="p-5 border-t border-slate-800 bg-slate-900">
            <p className="text-xs font-bold text-slate-500 mb-3 uppercase">Add Rule Block</p>
            <div className="grid grid-cols-2 gap-2">
              <Button size="sm" variant="secondary" onClick={() => handleAddRule(RuleType.TEXT)} icon={<Plus size={14}/>}>Text</Button>
              <Button size="sm" variant="secondary" onClick={() => handleAddRule(RuleType.DATE)} icon={<Plus size={14}/>}>Date</Button>
              <Button size="sm" variant="secondary" onClick={() => handleAddRule(RuleType.SEQUENCE)} icon={<Plus size={14}/>}>Sequence</Button>
              <Button size="sm" variant="secondary" onClick={() => handleAddRule(RuleType.ORIGINAL)} icon={<Plus size={14}/>}>Original Name</Button>
            </div>
          </div>
        </aside>

        {/* RIGHT PANEL: PREVIEW & FILES */}
        <section className="flex-1 flex flex-col bg-slate-950 relative overflow-hidden">

          {/* Toolbar */}
          <div className="h-14 border-b border-slate-800 flex items-center justify-between px-6 bg-slate-950/80">
            <div className="flex items-center gap-2">
               <label className="cursor-pointer">
                  <input type="file" multiple className="hidden" onChange={handleFileUpload} />
                  <Button variant="secondary" size="sm" icon={<FolderOpen size={16} />}>Add Files</Button>
               </label>
               {files.length > 0 && (
                 <Button variant="ghost" size="sm" onClick={handleClearFiles} icon={<Trash2 size={16} />} className="text-red-400 hover:text-red-300 hover:bg-red-900/20">
                   Clear All
                 </Button>
               )}
            </div>

            <div className="flex items-center gap-4">
              <div className="flex items-center gap-1 bg-slate-900 rounded-lg p-1 border border-slate-800">
                <button 
                  onClick={() => handleSort('name')}
                  className={`px-3 py-1 rounded text-xs font-medium transition-colors ${sortConfig.field === 'name' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  Name
                </button>
                <button 
                  onClick={() => handleSort('date')}
                  className={`px-3 py-1 rounded text-xs font-medium transition-colors ${sortConfig.field === 'date' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  Date
                </button>
                 <button 
                   onClick={() => handleSort('name')} 
                   className="px-2 text-slate-500 hover:text-white"
                   title="Toggle Direction"
                 >
                   <ArrowUpDown size={14} className={sortConfig.direction === 'desc' ? 'transform rotate-180' : ''} />
                 </button>
              </div>
            </div>
          </div>

          {/* File Table Header */}
          <div className="grid grid-cols-12 gap-4 px-6 py-3 border-b border-slate-800 text-xs font-bold text-slate-500 uppercase tracking-wider bg-slate-900/30">
             <div className="col-span-4">Original Filename</div>
             <div className="col-span-1"></div>
             <div className="col-span-4 text-otis-accent">New Filename</div>
             <div className="col-span-2 text-right">Size</div>
             <div className="col-span-1 text-right">Ext</div>
          </div>

          {/* File List */}
          <div className="flex-1 overflow-y-auto custom-scrollbar p-0">
            {files.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-slate-600 opacity-50">
                 <Archive size={64} strokeWidth={1} className="mb-4" />
                 <p className="text-lg font-medium">No files loaded</p>
                 <p className="text-sm">Drag and drop files here or click "Add Files"</p>
              </div>
            ) : (
              <ul className="divide-y divide-slate-800/50">
                {previewFiles.map((file) => (
                  <li key={file.id} className="grid grid-cols-12 gap-4 px-6 py-3 hover:bg-slate-900/40 transition-colors items-center group">
                    <div className="col-span-4 text-sm text-slate-400 truncate font-mono" title={file.originalName}>
                      {file.originalName}
                    </div>

                    <div className="col-span-1 flex justify-center text-slate-700">
                      →
                    </div>

                    <div className="col-span-4 text-sm text-white truncate font-mono font-medium" title={file.newName}>
                       {file.newName}
                    </div>

                    <div className="col-span-2 text-right text-xs text-slate-500 font-mono">
                      {formatBytes(file.size)}
                    </div>

                    <div className="col-span-1 text-right text-xs text-slate-600 font-bold uppercase">
                      {file.extension}
                    </div>
                  </li>
                ))}
              </ul>
            )}
          </div>

          {/* Action Bar */}
          <div className="h-20 border-t border-slate-800 bg-slate-900 flex items-center justify-between px-8">
            <div className="flex flex-col">
              <span className="text-xs text-slate-500 uppercase tracking-wider font-bold">Total Files</span>
              <span className="text-2xl font-mono text-white">{files.length}</span>
            </div>

            <div className="flex gap-4">
              <Button 
                variant="primary" 
                size="lg" 
                disabled={files.length === 0 || isProcessing} 
                onClick={handleDownloadZip}
                icon={isProcessing ? <RefreshCw size={20} className="animate-spin"/> : <Download size={20} />}
                className="shadow-lg shadow-otis-accent/20"
              >
                {isProcessing ? 'Processing...' : 'Process & Download ZIP'}
              </Button>
            </div>
          </div>

        </section>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  FilePlus, 
  Download, 
  Trash2, 
  ArrowUpDown, 
  RefreshCw,
  Plus,
  FolderOpen,
  LayoutGrid,
  List as ListIcon,
  Archive
} from 'lucide-react';
import { Rule, RuleType, FileData, SortConfig } from './types';
import { generateNewNames, createZip, formatBytes } from './utils/fileHelpers';
import { Button } from './components/Button';
import { RuleItem } from './components/RuleItem';
import JSZip from 'jszip';
import { saveAs } from 'file-saver';

// We need file-saver for client side downloading from blobs effectively
// Since I can't npm install in this environment description, I will implement a simple download helper or use the native anchor tag method if file-saver is strictly external.
// Actually, standard anchor download is fine for modern browsers.

const App: React.FC = () => {
  // State
  const [files, setFiles] = useState<FileData[]>([]);
  const [rules, setRules] = useState<Rule[]>([]);
  const [sortConfig, setSortConfig] = useState<SortConfig>({ field: 'name', direction: 'asc' });
  const [isProcessing, setIsProcessing] = useState(false);
  const [isDragging, setIsDragging] = useState(false);

  // Initialize with a default rule
  useEffect(() => {
    if (rules.length === 0) {
      setRules([{ id: uuidv4(), type: RuleType.ORIGINAL }]);
    }
  }, []);

  // Helper to sort files
  const sortFiles = (fileList: FileData[], config: SortConfig) => {
    return [...fileList].sort((a, b) => {
      let valA: string | number = '';
      let valB: string | number = '';

      if (config.field === 'name') {
        valA = a.originalName.toLowerCase();
        valB = b.originalName.toLowerCase();
      } else if (config.field === 'date') {
        valA = a.lastModified;
        valB = b.lastModified;
      } else if (config.field === 'size') {
        valA = a.size;
        valB = b.size;
      }

      if (valA < valB) return config.direction === 'asc' ? -1 : 1;
      if (valA > valB) return config.direction === 'asc' ? 1 : -1;
      return 0;
    });
  };

  // Shared file processing logic
  const processFiles = (uploadedFiles: File[]) => {
    const newFiles: FileData[] = uploadedFiles.map(file => {
      const lastDot = file.name.lastIndexOf('.');
      const name = lastDot !== -1 ? file.name.substring(0, lastDot) : file.name;
      const ext = lastDot !== -1 ? file.name.substring(lastDot + 1) : '';

      return {
        id: uuidv4(),
        file,
        originalName: file.name,
        newName: file.name, // Initial placeholder
        extension: ext,
        size: file.size,
        lastModified: file.lastModified
      };
    });

    setFiles(prev => sortFiles([...prev, ...newFiles], sortConfig));
  };

  // Handlers
  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files.length > 0) {
      processFiles(Array.from(event.target.files));
    }
    event.target.value = '';
  };

  // Drag and Drop Handlers
  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    // Check if we're actually leaving the container and not just entering a child
    if (e.currentTarget.contains(e.relatedTarget as Node)) return;
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      processFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleAddRule = (type: RuleType) => {
    const newRule: Rule = {
      id: uuidv4(),
      type,
      value: '',
      startNumber: 1,
      padding: 3,
      dateFormat: 'yyyyMMdd'
    };
    setRules(prev => [...prev, newRule]);
  };

  const handleUpdateRule = (id: string, updates: Partial<Rule>) => {
    setRules(prev => prev.map(r => r.id === id ? { ...r, ...updates } : r));
  };

  const handleRemoveRule = (id: string) => {
    setRules(prev => prev.filter(r => r.id !== id));
  };

  const handleSort = (field: 'name' | 'date' | 'size') => {
    const isSameField = sortConfig.field === field;
    const direction = isSameField && sortConfig.direction === 'asc' ? 'desc' : 'asc';
    const config: SortConfig = { field, direction };
    setSortConfig(config);
    setFiles(prev => sortFiles(prev, config));
  };

